@using sv_d9d2755665ec4c5d99a9e812a0658051.Components.Pages
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="d-flex flex-row">
    @* ─── Left Sidebar (Filters) ─── *@
    <div class="pe-3" style="min-width: 25%; max-width: 25%;">
        <div class="card">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                @* Category checkboxes *@
                <h6>Category</h6>
                @if (categories is not null)
                {
                    @foreach (var cat in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }
                else
                {
                    <p class="text-muted small">Loading…</p>
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small">Min Price</label>
                    <input type="number" class="form-control form-control-sm" min="0"
                           @bind="minPrice" @bind:event="onchange" />
                </div>
                <div class="mb-2">
                    <label class="form-label small">Max Price</label>
                    <input type="number" class="form-control form-control-sm" min="0"
                           @bind="maxPrice" @bind:event="onchange" />
                </div>

                <hr />

                @* In-stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                @* Action buttons *@
                <button class="btn btn-primary btn-sm w-100 mb-2" @onclick="ApplyFilters">
                    Apply Filters
                </button>
                <button class="btn btn-outline-secondary btn-sm w-100" @onclick="ClearFilters">
                    Clear Filters
                </button>
            </div>
        </div>
    </div>

    @* ─── Main Content ─── *@
    <div class="flex-grow-1">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger">@errorMessage</div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else if (result is not null)
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label mb-0 me-2 small">Sort by</label>
                    <select class="form-select form-select-sm d-inline-block w-auto"
                            @bind="sortBy" @bind:after="LoadProducts">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    Showing @ShowingRange of @result.TotalCount products
                </span>
            </div>

            @if (result.Items.Count == 0)
            {
                <div class="alert alert-info">No products match your filters.</div>
            }
            else
            {
                @* Product grid *@
                <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 mb-3">
                    @foreach (var product in result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductSelected="HandleProductSelected"
                                         OnAddToCart="HandleAddToCart" />
                        </div>
                    }
                </div>

                @* Pagination *@
                <nav>
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage - 1)">Previous</button>
                        </li>
                        @for (int i = 1; i <= TotalPages; i++)
                        {
                            var pageNum = i;
                            <li class="page-item @(pageNum == currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                            </li>
                        }
                        <li class="page-item @(currentPage == TotalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage + 1)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </div>
</div>

@code {
    // Filter state
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    // Search state
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;
    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / PageSize);

    private string ShowingRange
    {
        get
        {
            if (result is null || result.TotalCount == 0) return "0";
            int start = (result.Page - 1) * result.PageSize + 1;
            int end = Math.Min(start + result.Items.Count - 1, result.TotalCount);
            return $"{start}–{end}";
        }
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadCategories();
        await LoadProducts();
    }

    private async Task LoadCategories()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            categories = new List<string>();
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await LoadProducts();
    }

    private Task HandleProductSelected(Product product)
    {
        // Parent or navigation logic — EventCallback surfaces this to the hosting component
        return Task.CompletedTask;
    }

    private Task HandleAddToCart(Product product)
    {
        return Task.CompletedTask;
    }
}
"}

